mapper.select:
SELECT request_id, user_key, group_name, description, requested_at, status, reject_reason, updated_by_user_key, status_updated_at FROM group_create_request
status = #{status}
AND status != 'PROCESSING'
AND group_name LIKE CONCAT('%', #{groupName}, '%')
ORDER BY requested_at DESC LIMIT #{limit} OFFSET #{offset}

